03-15T22:26:48+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"tr"},{"@type":"Person","@id":"https://roadtostudy.com/author/murat/","name":"Murat","url":"https://roadtostudy.com/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"tr"}},{"@type":"BlogPosting","headline":"Nükleer Enerji Eğitimi Türkiye 2025: Bölüm, Üniversite, Kariyer","keywords":"nükleer enerji","datePublished":"2025-04-21T13:52:19+03:00","dateModified":"2026-03-15T22:26:48+03:00","articleSection":"Üniversite ve Programlar","author":{"@id":"https://roadtostudy.com/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Türkiye&#039;de nükleer enerji ve radyasyon güvenliği eğitimi hakkında bilmen gereken her şey burada. Hemen keşfet, geleceğine yön ver!","name":"Nükleer Enerji Eğitimi Türkiye 2025: Bölüm, Üniversite, Kariyer","@id":"https://roadtostudy.com/turkiyede-nukleer-enerji-ve-radyasyon-bilimleri/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/turkiyede-nukleer-enerji-ve-radyasyon-bilimleri/#webpage"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/turkiyede-nukleer-enerji-ve-radyasyon-bilimleri/#webpage"}}]}]}', "content_html" = '<div class="wp-block-rank-math-toc-block" id="rank-math-toc"><h2>İçindekiler</h2><nav><ol><li class=""><a href="#nukleer-teknoloji-ve-radyasyon-guvenligi-bolumu-nedir">Nükleer Teknoloji ve Radyasyon Güvenliği Bölümü Nedir?</a><ol></ol></li><li class=""><a href="#turkiyede-bu-bolumu-sunan-universiteler-hangileri">Türkiye&#8217;de Bu Bölümü Sunan Üniversiteler Hangileri?</a></li><li class=""><a href="#hangi-bolumlere-gecis-yapabilirsiniz">Hangi Bölümlere Geçiş Yapabilirsiniz?</a><ol></ol></